mapper.select:
SELECT t.date as date, CASE t.dayOfWeek WHEN 1 THEN '星期日' WHEN 2 THEN '星期一' WHEN 3 THEN '星期二' WHEN 4 THEN '星期三' WHEN 5 THEN '星期四' WHEN 6 THEN '星期五' WHEN 7 THEN '星期六' END as dayOfWeek, COALESCE(SUM(CASE WHEN t.type = 1 THEN t.amount ELSE 0 END), 0) as totalExpense, COALESCE(SUM(CASE WHEN t.type = 2 THEN t.amount ELSE 0 END), 0) as totalIncome FROM ( SELECT DATE(r.record_date) as date, DAYOFWEEK(DATE(r.record_date)) as dayOfWeek, r.type, r.amount FROM record r WHERE r.user_id = #{userId} AND r.del_flag = 0
AND DATE_FORMAT(r.record_date, '%Y-%m') = #{month}
AND r.type = #{type}
) t GROUP BY t.date, t.dayOfWeek ORDER BY t.date DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT DATE(r.record_date))
FROM record r
WHERE r.user_id = #{userId}
  AND r.del_flag = 0

  AND DATE_FORMAT(r.record_date, '%Y-%m') = #{month}


  AND r.type = #{type}

SELECT r.id, r.type, r.category_id as categoryId, c.name as categoryName, c.icon as categoryIcon, r.amount, r.remark, r.create_time as createTime FROM record r LEFT JOIN category c ON r.category_id = c.id AND c.del_flag = 0 WHERE r.user_id = #{userId} AND DATE(r.record_date) = #{date} AND r.del_flag = 0
AND r.type = #{type}
ORDER BY r.create_time DESC

SELECT
    DATE(record_date) AS date,
    COALESCE(SUM(amount), 0) AS amount
FROM record
WHERE user_id = #{userId}
  AND del_flag = 0
  AND record_date >= #{startDate}
  AND record_date <= #{endDate}

  AND type = #{type}

GROUP BY DATE(record_date)
ORDER BY DATE(record_date)

SELECT
    DATE_FORMAT(record_date, '%Y-%m') AS month,
    COALESCE(SUM(amount), 0) AS amount
FROM record
WHERE user_id = #{userId}
  AND del_flag = 0
  AND YEAR(record_date) = #{year}

  AND type = #{type}

GROUP BY DATE_FORMAT(record_date, '%Y-%m')
ORDER BY month
